class Solution:
    def maximumLength(self, nums) -> int:
        # Case 1: all even
        all_even = sum(1 for x in nums if x % 2 == 0)
        # Case 2: all odd
        all_odd = sum(1 for x in nums if x % 2 == 1)
        # Case 3: alternating
        alt = 0
        last_parity = -1
        for x in nums:
            p = x % 2
            if last_parity == -1 or p != last_parity:
                alt += 1
                last_parity = p
        return max(all_even, all_odd, alt)

