class Solution:
    def maximumLength(self, nums) -> int:
        evens = sum(1 for x in nums if x % 2 == 0)
        odds = len(nums) - evens
        alt, last = 0, -1
        for x in nums:
            p = x % 2
            if p != last:
                alt += 1
                last = p
        return max(evens, odds, alt)

