var maximumLength = function(nums) {
    let evens = 0, odds = 0;
    for (const x of nums) {
        if (x % 2 === 0) evens++; else odds++;
    }
    let alt = 0, last = -1;
    for (const x of nums) {
        const p = x % 2;
        if (p !== last) { alt++; last = p; }
    }
    return Math.max(evens, odds, alt);
};
